1	//! Unicode pretty-printer for trace formulas, calibrated from the oracle
2	//! (e.g. ks1 lemma L2 -> "∀ x #i #j. (Act( x ) @ #i) ⇒ (x = x)").
3	//!
4	//! `pp_formula` renders on a single line (byte-exact when the oracle keeps the
5	//! formula on one line). `pp_formula_wrapped` reproduces the oracle's multi-line
6	//! layout for wide formulas via a small HughesPJ-style document engine
7	//! (calibrated against probes r3_gw / r3_qm): a binary connective breaks after
8	//! its operator with the right operand hanging at the connective's starting
9	//! column, and a quantifier breaks after the `.` with its body hanging two
10	//! columns past the formula's base indent. See BEHAVIOR.md.
11	
12	use crate::ast::*;
13	use crate::pretty::{pp_fact, pp_term};
14	
15	pub fn pp_formula(f: &Formula) -> String {
16	    match f {
17	        Formula::False => "⊥".to_string(),
18	        Formula::True => "⊤".to_string(),
19	        Formula::Atom(a) => pp_atom(a),
20	        Formula::Not(g) => format!("¬({})", pp_formula(g)),
21	        Formula::And(a, b) => format!("({}) ∧ ({})", pp_formula(a), pp_formula(b)),
22	        Formula::Or(a, b) => format!("({}) ∨ ({})", pp_formula(a), pp_formula(b)),
23	        Formula::Implies(a, b) => format!("({}) ⇒ ({})", pp_formula(a), pp_formula(b)),
24	        Formula::Iff(a, b) => format!("({}) ⇔ ({})", pp_formula(a), pp_formula(b)),
25	        Formula::Forall(vs, g) => format!("∀ {}. {}", pp_bound_vars(vs), pp_formula(g)),
26	        Formula::Exists(vs, g) => format!("∃ {}. {}", pp_bound_vars(vs), pp_formula(g)),
27	    }
28	}
29	
30	fn pp_bound_vars(vs: &[VarSpec]) -> String {
31	    vs.iter()
32	        .map(crate::pretty::pp_var)
33	        .collect::<Vec<_>>()
34	        .join(" ")
35	}
36	
37	fn pp_atom(a: &Atom) -> String {
38	    match a {
39	        Atom::Eq(x, y) => format!("{} = {}", pp_term(x), pp_term(y)),
40	        Atom::Less(x, y) => format!("{} < {}", pp_term(x), pp_term(y)),
41	        Atom::LessMset(x, y) => format!("{} ⋖ {}", pp_term(x), pp_term(y)),
42	        Atom::Subterm(x, y) => format!("{} ⊏ {}", pp_term(x), pp_term(y)),
43	        Atom::Action(f, t) => format!("{} @ {}", pp_fact(f), pp_term(t)),
44	        Atom::Last(t) => format!("last({})", pp_term(t)),
45	        Atom::Pred(f) => pp_fact(f),
46	    }
47	}
48	
49	// ---------------------------------------------------------------------------
50	// Multi-line layout for wide formulas
51	// ---------------------------------------------------------------------------
52	
53	/// Effective page width for the formula printer (measured: a wide formula's
54	/// single line fits at total column 72 and breaks by 74 - probes r3_qm).
55	pub const FORMULA_WIDTH: usize = 72;
56	
57	/// A layout document. `Beside` glues children horizontally. `Group` is an
58	/// all-or-nothing break point: it is laid flat when it fits on the current line,
59	/// otherwise the first child stays on the current line and each following child
60	/// starts a new line indented to the group's own start column plus `hang`.
61	enum Doc {
62	    Text(String),
63	    Beside(Vec<Doc>),
64	    Group(Vec<Doc>, usize),
65	}
66	
67	fn flat(d: &Doc) -> String {
68	    match d {
69	        Doc::Text(s) => s.clone(),
70	        Doc::Beside(ds) => ds.iter().map(flat).collect(),
71	        Doc::Group(ds, _) => ds.iter().map(flat).collect::<Vec<_>>().join(" "),
72	    }
73	}
74	
75	/// Lay `d` beginning at column `col`. Continuation lines break relative to the
76	/// column where the enclosing group started (`col + hang`). Returns the
77	/// rendered text (with baked-in leading spaces on continuation lines) and the
78	/// end column of the last line.
79	fn lay(d: &Doc, col: usize, width: usize) -> (String, usize) {
80	    match d {
81	        Doc::Text(s) => (s.clone(), col + s.chars().count()),
82	        Doc::Beside(ds) => {
83	            let mut out = String::new();
84	            let mut c = col;
85	            for x in ds {
86	                let (s, e) = lay(x, c, width);
87	                out.push_str(&s);
88	                c = e;
89	            }
90	            (out, c)
91	        }
92	        Doc::Group(ds, hang) => {
93	            let fw = flat(d).chars().count();
94	            if col + fw <= width {
95	                // Flat: children joined by single spaces, no internal breaks.
96	                let mut out = String::new();
97	                let mut c = col;
98	                for (i, x) in ds.iter().enumerate() {
99	                    if i > 0 {
100	                        out.push(' ');
101	                        c += 1;
102	                    }
103	                    let fs = flat(x);
104	                    c += fs.chars().count();
105	                    out.push_str(&fs);
106	                }
107	                (out, c)
108	            } else {
109	                // Broken: the first child stays on the current line; every
110	                // following child hangs at `col + hang` (the group's start
111	                // column plus its hang offset).
112	                let indent = col + hang;
113	                let (s0, _) = lay(&ds[0], col, width);
114	                let mut out = s0;
115	                for x in &ds[1..] {
116	                    out.push('\n');
117	                    out.push_str(&" ".repeat(indent));
118	                    let (s, _) = lay(x, indent, width);
119	                    out.push_str(&s);
120	                }
121	                let end = out.rsplit('\n').next().unwrap().chars().count();
122	                (out, end)
123	            }
124	        }
125	    }
126	}
127	
128	/// `(doc)` - the operand of a logical connective is always parenthesised.
129	fn parens(inner: Doc) -> Doc {
130	    Doc::Beside(vec![Doc::Text("(".into()), inner, Doc::Text(")".into())])
131	}
132	
133	fn binop_doc(a: &Formula, op: &str, b: &Formula) -> Doc {
134	    // Breaks after the operator; the right operand hangs at the connective's
135	    // start column (hang 0). Both operands are parenthesised.
136	    Doc::Group(
137	        vec![
138	            Doc::Beside(vec![parens(formula_doc(a)), Doc::Text(format!(" {}", op))]),
139	            parens(formula_doc(b)),
140	        ],
141	        0,
142	    )
143	}
144	
145	/// A relational atom `a OP b` (=, <, ⋖, ⊏): breaks after the operator with the
146	/// right term hanging at the atom's start column (hang 0). The term operands are
147	/// NOT parenthesised (only the whole atom is, by its enclosing connective).
148	fn relation_doc(a: &Term, op: &str, b: &Term) -> Doc {
149	    Doc::Group(
150	        vec![
151	            Doc::Text(format!("{} {}", pp_term(a), op)),
152	            Doc::Text(pp_term(b)),
153	        ],
154	        0,
155	    )
156	}
157	
158	fn atom_doc(a: &Atom) -> Doc {
159	    match a {
160	        Atom::Eq(x, y) => relation_doc(x, "=", y),
161	        Atom::Less(x, y) => relation_doc(x, "<", y),
162	        Atom::LessMset(x, y) => relation_doc(x, "⋖", y),
163	        Atom::Subterm(x, y) => relation_doc(x, "⊏", y),
164	        // Action, Last and Pred atoms are laid on a single line.
165	        Atom::Action(_, _) | Atom::Last(_) | Atom::Pred(_) => Doc::Text(pp_atom(a)),
166	    }
167	}
168	
169	fn formula_doc(f: &Formula) -> Doc {
170	    match f {
171	        Formula::False => Doc::Text("⊥".into()),
172	        Formula::True => Doc::Text("⊤".into()),
173	        Formula::Atom(a) => atom_doc(a),
174	        Formula::Not(g) => Doc::Beside(vec![Doc::Text("¬".into()), parens(formula_doc(g))]),
175	        Formula::And(a, b) => binop_doc(a, "∧", b),
176	        Formula::Or(a, b) => binop_doc(a, "∨", b),
177	        Formula::Implies(a, b) => binop_doc(a, "⇒", b),
178	        Formula::Iff(a, b) => binop_doc(a, "⇔", b),
179	        Formula::Forall(vs, g) => quantifier_doc("∀", vs, g),
180	        Formula::Exists(vs, g) => quantifier_doc("∃", vs, g),
181	    }
182	}
183	
184	fn quantifier_doc(sym: &str, vs: &[VarSpec], g: &Formula) -> Doc {
185	    // Breaks after the dot; the body hangs one column past the quantifier's
186	    // start column (hang 1).
187	    let head = format!("{} {}.", sym, pp_bound_vars(vs));
188	    Doc::Group(vec![Doc::Text(head), formula_doc(g)], 1)
189	}
190	
191	/// Render a formula the way the oracle embeds it inside `"..."` in the
192	/// guardedness report: the formula's first character sits at column `col`
193	/// (the oracle uses column 7, i.e. after `      "`). Continuation lines carry
194	/// their absolute indentation. When the whole formula fits on one line the
195	/// output is byte-identical to [`pp_formula`].
196	pub fn pp_formula_wrapped(f: &Formula, col: usize) -> String {
197	    lay(&formula_doc(f), col, FORMULA_WIDTH).0
198	}
