55	// ---------------------------------------------------------------------------
56	// AST traversal helpers
57	// ---------------------------------------------------------------------------
58	
59	/// The protocol rules of a theory (excludes intruder rules).
60	pub fn protocol_rules(thy: &Theory) -> Vec<&Rule> {
61	    thy.items
62	        .iter()
63	        .filter_map(|it| match it {
64	            TheoryItem::Rule(r) => Some(r),
65	            _ => None,
66	        })
67	        .collect()
68	}
69	
70	fn collect_term_vars(t: &Term, out: &mut Vec<VarSpec>) {
71	    match t {
72	        Term::Var(v) => out.push(v.clone()),
73	        Term::App(_, args) | Term::Pair(args) => {
74	            for a in args {
75	                collect_term_vars(a, out);
76	            }
77	        }
78	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
79	            collect_term_vars(a, out);
80	            collect_term_vars(b, out);
81	        }
82	        Term::PatMatch(inner) => collect_term_vars(inner, out),
83	        _ => {}
84	    }
85	}
86	
87	fn collect_fact_vars(f: &Fact, out: &mut Vec<VarSpec>) {
88	    for a in &f.args {
89	        collect_term_vars(a, out);
90	    }
91	}
92	
93	fn collect_facts_vars(fs: &[Fact], out: &mut Vec<VarSpec>) {
94	    for f in fs {
95	        collect_fact_vars(f, out);
96	    }
97	}
98	
99	/// Collect public-constant literals (name only) from a term.
100	fn collect_pub_lits(t: &Term, out: &mut Vec<String>) {
101	    match t {
102	        Term::PubLit(s) => out.push(s.clone()),
103	        Term::App(_, args) | Term::Pair(args) => {
104	            for a in args {
105	                collect_pub_lits(a, out);
106	            }
107	        }
108	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
109	            collect_pub_lits(a, out);
110	            collect_pub_lits(b, out);
111	        }
112	        Term::PatMatch(inner) => collect_pub_lits(inner, out),
113	        _ => {}
114	    }
115	}
116	
117	/// Collect fresh-name literals (`~'foo'`) from a term, rendered as the oracle
118	/// prints them.
119	fn collect_fresh_lits(t: &Term, out: &mut Vec<String>) {
120	    match t {
121	        Term::FreshLit(_) => out.push(pp_term(t)),
122	        Term::App(_, args) | Term::Pair(args) => {
123	            for a in args {
124	                collect_fresh_lits(a, out);
125	            }
126	        }
127	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
128	            collect_fresh_lits(a, out);
129	            collect_fresh_lits(b, out);
130	        }
131	        Term::PatMatch(inner) => collect_fresh_lits(inner, out),
132	        _ => {}
133	    }
134	}
135	
136	/// Collect maximal multiplication (`*`) subterms of a term, rendered as the
137	/// oracle prints them. A product is maximal: its own operands are not
138	/// descended into.
139	fn collect_mult_terms(t: &Term, out: &mut Vec<String>) {
140	    if let Term::BinOp(BinOp::Mult, _, _) = t {
141	        out.push(pp_term(t));
142	        return;
143	    }
144	    match t {
145	        Term::App(_, args) | Term::Pair(args) => {
146	            for a in args {
147	                collect_mult_terms(a, out);
148	            }
149	        }
150	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
151	            collect_mult_terms(a, out);
152	            collect_mult_terms(b, out);
153	        }
154	        Term::PatMatch(inner) => collect_mult_terms(inner, out),
155	        _ => {}
156	    }
157	}
