159	/// Indent every line of a (possibly multi-line) block by `n` spaces.
160	fn indent_block(s: &str, n: usize) -> String {
161	    let pad = " ".repeat(n);
162	    s.lines()
163	        .map(|l| format!("{}{}", pad, l))
164	        .collect::<Vec<_>>()
165	        .join("\n")
166	}
167	
168	/// Word-fill (Wadler/Leijen `fillSep`) at the given `width` with a leading
169	/// `indent` of spaces on every line. A word is pushed onto the current line
170	/// while it fits (column + 1 + word <= width), otherwise a new line begins.
171	fn fill_words(words: &[String], indent: usize, width: usize) -> String {
172	    let pad = " ".repeat(indent);
173	    let mut lines: Vec<String> = Vec::new();
174	    let mut cur = String::new();
175	    let mut col = 0usize;
176	    for w in words {
177	        let wlen = w.chars().count();
178	        if cur.is_empty() {
179	            cur = format!("{}{}", pad, w);
180	            col = indent + wlen;
181	        } else if col + 1 + wlen <= width {
182	            cur.push(' ');
183	            cur.push_str(w);
184	            col += 1 + wlen;
185	        } else {
186	            lines.push(std::mem::take(&mut cur));
187	            cur = format!("{}{}", pad, w);
188	            col = indent + wlen;
189	        }
190	    }
191	    if !cur.is_empty() {
192	        lines.push(cur);
193	    }
194	    lines.join("\n")
195	}
196	
197	fn var_needs_binding(v: &VarSpec) -> bool {
198	    matches!(
199	        v.sort,
200	        SortHint::Fresh | SortHint::Msg | SortHint::Untagged | SortHint::Nat
201	    )
202	}
203	
204	fn var_key(v: &VarSpec) -> (String, u64, i32) {
205	    (v.name.clone(), v.idx, sort_rank(v.sort))
206	}
207	
208	fn sort_rank(s: SortHint) -> i32 {
209	    match s {
210	        SortHint::Msg => 0,
211	        SortHint::Pub => 1,
212	        SortHint::Fresh => 2,
213	        SortHint::Node => 3,
214	        SortHint::Nat => 4,
215	        SortHint::Untagged => 5,
216	        SortHint::Suffix(_) => 6,
217	    }
218	}
219	
220	fn dedup_vars(mut vs: Vec<VarSpec>) -> Vec<VarSpec> {
221	    vs.sort_by_key(var_key);
222	    vs.dedup_by_key(|v| var_key(v));
223	    vs
224	}
