226	// ---------------------------------------------------------------------------
227	// 1. Unbound variables
228	// ---------------------------------------------------------------------------
229	pub fn unbound_variables(thy: &Theory) -> Vec<WfError> {
230	    let mut entries: Vec<String> = Vec::new();
231	    for r in protocol_rules(thy) {
232	        // Bound = variables in premises plus let-bound variables.
233	        let mut bound: Vec<VarSpec> = Vec::new();
234	        collect_facts_vars(&r.premises, &mut bound);
235	        for lb in &r.let_block {
236	            collect_term_vars(&lb.var, &mut bound);
237	        }
238	        let bound: std::collections::HashSet<(String, u64, i32)> =
239	            bound.iter().map(var_key).collect();
240	
241	        // Used = variables in actions, conclusions, embedded restrictions,
242	        // and the right-hand-sides of let bindings.
243	        let mut used: Vec<VarSpec> = Vec::new();
244	        collect_facts_vars(&r.actions, &mut used);
245	        collect_facts_vars(&r.conclusions, &mut used);
246	        for lb in &r.let_block {
247	            collect_term_vars(&lb.value, &mut used);
248	        }
249	
250	        let mut unbound: Vec<VarSpec> = used
251	            .into_iter()
252	            .filter(var_needs_binding)
253	            .filter(|v| !bound.contains(&var_key(v)))
254	            .collect();
255	        unbound = dedup_vars(unbound);
256	        // Report order: by base name then index.
257	        unbound.sort_by(|a, b| a.name.cmp(&b.name).then(a.idx.cmp(&b.idx)));
258	
259	        if !unbound.is_empty() {
260	            let names: Vec<String> = unbound.iter().map(pp_var).collect();
261	            entries.push(format!(
262	                "  rule `{}' has unbound variables: \n    {}",
263	                r.name,
264	                names.join(", ")
265	            ));
266	        }
267	    }
268	    if entries.is_empty() {
269	        vec![]
270	    } else {
271	        vec![WfError::new(T_UNBOUND, entries.join("\n  \n"))]
272	    }
273	}
274	
275	// ---------------------------------------------------------------------------
276	// 3. Variable with mismatching sorts or capitalization
277	// ---------------------------------------------------------------------------
278	pub fn mismatching_sorts(thy: &Theory) -> Vec<WfError> {
279	    let mut rule_entries: Vec<String> = Vec::new();
280	    for r in protocol_rules(thy) {
281	        let mut vars: Vec<VarSpec> = Vec::new();
282	        collect_facts_vars(&r.premises, &mut vars);
283	        collect_facts_vars(&r.actions, &mut vars);
284	        collect_facts_vars(&r.conclusions, &mut vars);
285	
286	        // Group by lowercased base name; a group with >1 distinct variant
287	        // (prefix+name, ignoring index) is a conflict.
288	        let mut groups: Vec<(String, Vec<String>)> = Vec::new(); // (lc key, variants)
289	        for v in &vars {
290	            let key = v.name.to_lowercase();
291	            let variant = variant_repr(v);
292	            match groups.iter_mut().find(|(k, _)| *k == key) {
293	                Some((_, variants)) => {
294	                    if !variants.contains(&variant) {
295	                        variants.push(variant);
296	                    }
297	                }
298	                None => groups.push((key, vec![variant])),
299	            }
300	        }
301	        let mut conflicts: Vec<Vec<String>> = groups
302	            .into_iter()
303	            .filter(|(_, vs)| vs.len() > 1)
304	            .map(|(_, mut vs)| {
305	                vs.sort();
306	                vs
307	            })
308	            .collect();
309	        if conflicts.is_empty() {
310	            continue;
311	        }
312	        // deterministic ordering of groups within a rule
313	        conflicts.sort();
314	        let mut body = format!("  rule `{}': ", r.name);
315	        for (i, variants) in conflicts.iter().enumerate() {
316	            body.push_str(&format!("\n    {}. {}", i + 1, variants.join(", ")));
317	        }
318	        rule_entries.push(body);
319	    }
320	    if rule_entries.is_empty() {
321	        return vec![];
322	    }
323	    let header = "Possible reasons:\n1. Identifiers are case sensitive, i.e.,'x' and 'X' are considered to be different.\n2. The same holds for sorts:, i.e., '$x', 'x', and '~x' are considered to be different.\n";
324	    let msg = format!("{}\n{}", header, rule_entries.join("\n  \n"));
325	    vec![WfError::new(T_SORTS, msg)]
326	}
327	
328	/// A variable's sort+name representation without the numeric index.
329	fn variant_repr(v: &VarSpec) -> String {
330	    let prefix = match v.sort {
331	        SortHint::Fresh => "~",
332	        SortHint::Pub => "$",
333	        SortHint::Nat => "%",
334	        SortHint::Node => "#",
335	        _ => "",
336	    };
337	    format!("{}{}", prefix, v.name)
338	}
339	
340	// ---------------------------------------------------------------------------
341	// 4. Reserved names
342	// ---------------------------------------------------------------------------
343	pub fn reserved_names(thy: &Theory) -> Vec<WfError> {
344	    let mut entries: Vec<String> = Vec::new();
345	    for r in protocol_rules(thy) {
346	        // On the left/right the reserved set is {K,KU,KD}; in the middle
347	        // (actions) the I/O facts In/Out/Fr are reserved too (observed z9/z11).
348	        for (facts, phrase, middle) in [
349	            (&r.premises, "left-hand-side", false),
350	            (&r.actions, "the middle", true),
351	            (&r.conclusions, "the right-hand-side", false),
352	        ] {
353	            let hits: Vec<&Fact> = facts
354	                .iter()
355	                .filter(|f| is_reserved(&f.name) || (middle && is_special(&f.name)))
356	                .collect();
357	            if hits.is_empty() {
358	                continue;
359	            }
360	            let rendered: Vec<String> = hits.iter().map(|f| pp_fact(f)).collect();
361	            entries.push(format!(
362	                "  Rule `{}' contains facts with reserved names on {}:\n    {}",
363	                r.name,
364	                phrase,
365	                rendered.join(", ")
366	            ));
367	        }
368	    }
369	    if entries.is_empty() {
370	        vec![]
371	    } else {
372	        vec![WfError::new(T_RESERVED, entries.join("\n  \n"))]
373	    }
374	}
