382	        for facts in [&r.premises, &r.conclusions] {
383	            for f in facts {
384	                if f.name != "Fr" {
385	                    continue;
386	                }
387	                let ok = f.args.len() == 1
388	                    && matches!(
389	                        &f.args[0],
