451	struct FactUse {
452	    label: &'static str, // "Rule" or "Lemma"
453	    owner: String,       // rule/lemma name
454	    arity: usize,
455	    persistent: bool,
456	    render: String, // pp_fact for rules; raw Haskell `Fact {..}` show for lemmas
457	}
458	
459	/// Raw Haskell `Show` of a lemma-sourced fact, as the oracle prints it in the
460	/// arity/multiplicity blocks (observed r3_lemarity / r3_lemmult):
461	///   Fact {factTag = ProtoFact Linear "Act" 2, factAnnotations = fromList [],
462	///         factTerms = [Bound 2,Bound 1]}
463	/// `factTerms` uses the same de Bruijn / Free rendering as the Formula-terms
464	/// check (the binder `stack` is the quantifier context at the atom).
465	fn show_haskell_fact(f: &Fact, stack: &[Binder]) -> String {
466	    let mult = if f.persistent { "Persistent" } else { "Linear" };
467	    let terms: Vec<String> = f.args.iter().map(|a| show_wf_term(a, stack)).collect();
468	    format!(
469	        "Fact {{factTag = ProtoFact {} \"{}\" {}, factAnnotations = fromList [], factTerms = [{}]}}",
470	        mult,
471	        f.name,
472	        f.args.len(),
473	        terms.join(",")
474	    )
475	}
