477	/// Collect action-fact uses from a lemma formula (label "Lemma"), tracking the
478	/// quantifier binder stack for the de Bruijn rendering of the fact terms.
479	fn gather_formula_facts(
480	    f: &Formula,
481	    stack: &mut Vec<Binder>,
482	    owner: &str,
483	    out: &mut Vec<(String, FactUse)>,
484	) {
485	    match f {
486	        Formula::False | Formula::True => {}
487	        Formula::Atom(Atom::Action(fact, _)) => {
488	            out.push((
489	                fact.name.clone(),
490	                FactUse {
491	                    label: "Lemma",
492	                    owner: owner.to_string(),
493	                    arity: fact.args.len(),
494	                    persistent: fact.persistent,
495	                    render: show_haskell_fact(fact, stack),
496	                },
497	            ));
498	        }
499	        Formula::Atom(_) => {}
500	        Formula::Not(g) => gather_formula_facts(g, stack, owner, out),
501	        Formula::And(a, b)
502	        | Formula::Or(a, b)
503	        | Formula::Implies(a, b)
504	        | Formula::Iff(a, b) => {
505	            gather_formula_facts(a, stack, owner, out);
506	            gather_formula_facts(b, stack, owner, out);
507	        }
508	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
509	            let n = vs.len();
510	            for v in vs {
511	                stack.push((v.name.clone(), var_class(v)));
512	            }
513	            gather_formula_facts(g, stack, owner, out);
514	            for _ in 0..n {
515	                stack.pop();
516	            }
517	        }
518	    }
519	}
520	
521	/// Gather every fact occurrence in the theory (name -> uses) in source order.
522	/// Protocol rules contribute their premise/action/conclusion facts (rendered by
523	/// the term pretty-printer); lemmas contribute their formula action facts
524	/// (rendered as the raw Haskell `Fact {..}` show). Restrictions do NOT
525	/// contribute (observed r3_restrarity: a restriction action arity mismatch is
526	/// silent).
527	fn gather_fact_uses(thy: &Theory) -> Vec<(String, Vec<FactUse>)> {
528	    let mut map: Vec<(String, Vec<FactUse>)> = Vec::new();
529	    let push = |name: String, u: FactUse, map: &mut Vec<(String, Vec<FactUse>)>| {
530	        match map.iter_mut().find(|(n, _)| *n == name) {
531	            Some((_, uses)) => uses.push(u),
532	            None => map.push((name, vec![u])),
533	        }
534	    };
535	    for it in &thy.items {
536	        match it {
537	            TheoryItem::Rule(r) => {
538	                for facts in [&r.premises, &r.actions, &r.conclusions] {
539	                    for f in facts {
540	                        push(
541	                            f.name.clone(),
542	                            FactUse {
543	                                label: "Rule",
544	                                owner: r.name.clone(),
545	                                arity: f.args.len(),
546	                                persistent: f.persistent,
547	                                render: pp_fact(f),
548	                            },
549	                            &mut map,
550	                        );
551	                    }
552	                }
553	            }
554	            TheoryItem::Lemma(l) => {
555	                let mut stack: Vec<Binder> = Vec::new();
556	                let mut uses: Vec<(String, FactUse)> = Vec::new();
557	                gather_formula_facts(&l.formula, &mut stack, &l.name, &mut uses);
558	                for (name, u) in uses {
559	                    push(name, u, &mut map);
560	                }
561	            }
562	            _ => {}
563	        }
564	    }
565	    map
566	}
