568	fn render_fact_blocks(conflicts: &[(String, Vec<String>)], intro1: &str, intro2: &str) -> String {
569	    // conflicts: (lowercased fact name, item lines) already ordered.
570	    let mut body = format!("{}\n{}\n  ", intro1, intro2);
571	    for (i, (lname, items)) in conflicts.iter().enumerate() {
572	        let block = format!("  Fact `{}':\n\n{}\n  ", lname, items.join("\n    \n"));
573	        if i == 0 {
574	            body.push_str("\n\n");
575	        } else {
576	            body.push('\n');
577	        }
578	        body.push_str(&block);
579	    }
580	    body
581	}
