584	// Fact capitalization issues (precedes Fact arity issues)
585	// ---------------------------------------------------------------------------
586	// Fact names that are equal under ASCII-lowercasing but differ in their exact
587	// spelling (e.g. `Send` vs `SEND`) are distinct facts. Reported like the arity
588	// block, but EVERY occurrence is listed (no per-(rule,cap) deduplication -
589	// observed r3_capord: `Send` twice in one rule yields two items).
590	pub fn fact_capitalization(thy: &Theory) -> Vec<WfError> {
591	    struct Occ {
592	        name: String,
593	        rule: String,
594	        pp: String,
595	    }
596	    let mut occ: Vec<Occ> = Vec::new();
597	    for r in protocol_rules(thy) {
598	        for facts in [&r.premises, &r.actions, &r.conclusions] {
599	            for f in facts {
600	                occ.push(Occ {
601	                    name: f.name.clone(),
602	                    rule: r.name.clone(),
603	                    pp: pp_fact(f),
604	                });
605	            }
606	        }
607	    }
608	    // Group by lowercased name, preserving first-seen order.
609	    let mut groups: Vec<(String, Vec<&Occ>)> = Vec::new();
610	    for o in &occ {
611	        let key = o.name.to_lowercase();
612	        match groups.iter_mut().find(|(k, _)| *k == key) {
613	            Some((_, v)) => v.push(o),
614	            None => groups.push((key, vec![o])),
615	        }
616	    }
617	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
618	    for (key, os) in &groups {
619	        let distinct: std::collections::BTreeSet<&String> = os.iter().map(|o| &o.name).collect();
620	        if distinct.len() < 2 {
621	            continue; // no capitalization conflict
622	        }
623	        let items: Vec<String> = os
624	            .iter()
625	            .enumerate()
626	            .map(|(i, o)| {
627	                format!(
628	                    "    {}. Rule `{}', capitalization \"{}\"\n         {}",
629	                    i + 1,
630	                    o.rule,
631	                    o.name,
632	                    o.pp
633	                )
634	            })
635	            .collect();
636	        conflicts.push((key.clone(), items));
637	    }
638	    if conflicts.is_empty() {
639	        return vec![];
640	    }
641	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
642	    let msg = render_fact_blocks(
643	        &conflicts,
644	        "Fact names are case-sensitive, different capitalizations are considered as different facts, i.e., Fact() is different from FAct(). ",
645	        "Check the capitalization of your fact names.",
646	    );
647	    vec![WfError::new(T_FACT_CAP, msg)]
648	}
