650	pub fn fact_arity(thy: &Theory) -> Vec<WfError> {
651	    let uses = gather_fact_uses(thy);
652	    let mut conflicts: Vec<(String, Vec<String>)> = Vec::new();
653	    for (name, us) in &uses {
654	        let arities: std::collections::BTreeSet<usize> = us.iter().map(|u| u.arity).collect();
655	        if arities.len() < 2 {
656	            continue;
657	        }
658	        // one item per distinct (label, owner, arity), first render kept.
659	        let mut seen: Vec<(&str, String, usize)> = Vec::new();
660	        let mut items: Vec<String> = Vec::new();
661	        for u in us {
662	            let k = (u.label, u.owner.clone(), u.arity);
663	            if seen.contains(&k) {
664	                continue;
665	            }
666	            seen.push(k);
667	            let n = items.len() + 1;
668	            items.push(format!(
669	                "    {}. {} `{}', arity {}\n         {}",
670	                n, u.label, u.owner, u.arity, u.render
671	            ));
672	        }
673	        conflicts.push((name.to_lowercase(), items));
674	    }
675	    if conflicts.is_empty() {
676	        return vec![];
677	    }
678	    conflicts.sort_by(|a, b| a.0.cmp(&b.0));
679	    let msg = render_fact_blocks(
680	        &conflicts,
681	        "Same fact is used with different arities, i.e., Fact('A','B') is different from Fact('A'). ",
682	        "Check the arguments of your facts.",
683	    );
684	    vec![WfError::new(T_ARITY, msg)]
685	}
