751	pub fn fact_lhs_occur_no_rhs(thy: &Theory) -> Vec<WfError> {
752	    let mut lhs: Vec<FactId> = Vec::new();
753	    let mut rhs: Vec<FactId> = Vec::new();
754	    for r in protocol_rules(thy) {
755	        for f in &r.premises {
756	            if is_builtin_factname(&f.name) {
757	                continue;
758	            }
759	            lhs.push(FactId {
760	                name: f.name.clone(),
761	                arity: f.args.len(),
762	                persistent: f.persistent,
763	                rule: r.name.clone(),
764	            });
765	        }
766	        for f in &r.conclusions {
767	            if is_builtin_factname(&f.name) {
768	                continue;
769	            }
770	            rhs.push(FactId {
771	                name: f.name.clone(),
772	                arity: f.args.len(),
773	                persistent: f.persistent,
774	                rule: r.name.clone(),
775	            });
776	        }
777	    }
778	    let rhs_idents: std::collections::HashSet<(String, usize, bool)> =
779	        rhs.iter().map(|f| f.ident()).collect();
780	
781	    // LHS-only identities, first occurrence, in source order.
782	    let mut seen: Vec<(String, usize, bool)> = Vec::new();
783	    let mut items: Vec<String> = Vec::new();
784	    for f in &lhs {
785	        if rhs_idents.contains(&f.ident()) || seen.contains(&f.ident()) {
786	            continue;
787	        }
788	        seen.push(f.ident());
789	        let n = items.len() + 1;
790	        let mut line = format!("  {}. {}", n, f.render());
791	        if let Some(sugg) = nearest_rhs(&f.name, &rhs) {
792	            line.push_str(&format!(". Perhaps you want to use the fact {}", sugg.render()));
793	        }
794	        items.push(line);
795	    }
796	    if items.is_empty() {
797	        vec![]
798	    } else {
799	        vec![WfError::new(T_LHSRHS, items.join("\n  \n"))]
800	    }
801	}
