803	/// Nearest RHS fact by name edit distance, if within threshold (<= 3).
804	fn nearest_rhs<'a>(name: &str, rhs: &'a [FactId]) -> Option<&'a FactId> {
805	    let mut best: Option<(usize, &FactId)> = None;
806	    for f in rhs {
807	        let d = edit_distance(name, &f.name);
808	        match best {
809	            Some((bd, _)) if d >= bd => {}
810	            _ => best = Some((d, f)),
811	        }
812	    }
813	    match best {
814	        Some((d, f)) if d <= 3 => Some(f),
815	        _ => None,
816	    }
817	}
818	
819	fn edit_distance(a: &str, b: &str) -> usize {
820	    let a: Vec<char> = a.chars().collect();
821	    let b: Vec<char> = b.chars().collect();
822	    let mut prev: Vec<usize> = (0..=b.len()).collect();
823	    let mut cur = vec![0usize; b.len() + 1];
824	    for i in 1..=a.len() {
825	        cur[0] = i;
826	        for j in 1..=b.len() {
827	            let cost = if a[i - 1] == b[j - 1] { 0 } else { 1 };
828	            cur[j] = (prev[j] + 1).min(cur[j - 1] + 1).min(prev[j - 1] + cost);
829	        }
830	        std::mem::swap(&mut prev, &mut cur);
831	    }
832	    prev[b.len()]
833	}
