839	pub fn public_names_report(thy: &Theory) -> Vec<WfError> {
840	    let mut pairs: Vec<(String, String)> = Vec::new(); // (constName, ruleName)
841	    for r in protocol_rules(thy) {
842	        let mut names: Vec<String> = Vec::new();
843	        for facts in [&r.premises, &r.actions, &r.conclusions] {
844	            for f in facts {
845	                for a in &f.args {
846	                    collect_pub_lits(a, &mut names);
847	                }
848	            }
849	        }
850	        for n in names {
