860	pub fn public_names_report_from_pairs(pairs: Vec<(String, String)>) -> Vec<WfError> {
861	    // Group by lowercased constant name, preserving first-seen order.
862	    let mut groups: Vec<(String, Vec<(String, String)>)> = Vec::new();
863	    for (name, rule) in &pairs {
864	        let key = name.to_lowercase();
865	        match groups.iter_mut().find(|(k, _)| *k == key) {
866	            Some((_, v)) => v.push((name.clone(), rule.clone())),
867	            None => groups.push((key, vec![(name.clone(), rule.clone())])),
868	        }
869	    }
870	    let mut items: Vec<String> = Vec::new();
871	    for (_, occ) in &groups {
872	        let distinct: std::collections::BTreeSet<&String> = occ.iter().map(|(n, _)| n).collect();
873	        if distinct.len() < 2 {
874	            continue; // no capitalization conflict
875	        }
876	        // Group occurrences by rule, preserving first-seen rule order.
877	        let mut by_rule: Vec<(String, Vec<String>)> = Vec::new();
878	        for (n, rule) in occ {
879	            match by_rule.iter_mut().find(|(rr, _)| rr == rule) {
880	                Some((_, ns)) => {
881	                    if !ns.contains(n) {
882	                        ns.push(n.clone());
883	                    }
884	                }
885	                None => by_rule.push((rule.clone(), vec![n.clone()])),
886	            }
887	        }
888	        let locs: Vec<String> = by_rule
889	            .into_iter()
890	            .map(|(rule, mut ns)| {
891	                ns.sort();
892	                let quoted: Vec<String> = ns.iter().map(|n| format!("'{}'", n)).collect();
893	                format!("rule \"{}\":  name {}", rule, quoted.join(", "))
894	            })
895	            .collect();
896	        let n = items.len() + 1;
897	        items.push(format!("  {}. {}", n, locs.join(", ")));
898	    }
899	    if items.is_empty() {
900	        return vec![];
901	    }
902	    let header = "Identifiers are case-sensitive, mismatched capitalizations are considered as different, i.e., 'ID' is different from 'id'. Check the capitalization of your identifiers.";
903	    let msg = format!("{}\n\n{}", header, items.join("\n  \n"));
904	    vec![WfError::new(T_PUBNAMES, msg)]
905	}
