907	// ---------------------------------------------------------------------------
908	// Formula-variable sorts and sort-aware binding
909	// ---------------------------------------------------------------------------
910	// Formula quantifiers bind sorted variables. The oracle treats a bound variable
911	// and a use as the same variable only when they share a name AND a sort class,
912	// so a temporal binder `#x` does NOT bind a message-position use `x`. The parser
913	// tags an un-annotated message-position variable as `Untagged` and an annotated
914	// one as `Msg`; the oracle treats those as one variable, so both collapse to the
915	// `Msg` class here (this is what keeps a quantified message variable bound to its
916	// uses across the parser's tag differences).
917	
918	/// Sort equivalence class of a formula variable, used for binding and guarding.
919	#[derive(Clone, Copy, PartialEq, Eq, Hash)]
920	enum SortClass {
921	    Msg,
922	    Pub,
923	    Fresh,
924	    Node,
925	    Nat,
926	}
927	
928	fn sort_class(s: SortHint) -> SortClass {
929	    match s {
930	        SortHint::Msg | SortHint::Untagged | SortHint::Suffix(SuffixSort::Msg) => SortClass::Msg,
931	        SortHint::Pub | SortHint::Suffix(SuffixSort::Pub) => SortClass::Pub,
932	        SortHint::Fresh | SortHint::Suffix(SuffixSort::Fresh) => SortClass::Fresh,
933	        SortHint::Node | SortHint::Suffix(SuffixSort::Node) => SortClass::Node,
934	        SortHint::Nat | SortHint::Suffix(SuffixSort::Nat) => SortClass::Nat,
935	    }
936	}
937	
938	fn var_class(v: &VarSpec) -> SortClass {
939	    sort_class(v.sort)
940	}
941	
942	/// A binder on the quantifier stack: the bound variable's name and sort class.
943	type Binder = (String, SortClass);
944	
945	// ---------------------------------------------------------------------------
946	// Quantifier sorts (variables quantified over a disallowed sort)
947	// ---------------------------------------------------------------------------
948	// Quantifying over a public or fresh variable is rejected; message, temporal
949	// (node) and natural-number quantifiers are allowed. Each offending variable is
950	// reported as a Haskell `(name, LSort)` tuple, collected in binding order.
951	
952	fn wrong_lsort(s: SortHint) -> Option<&'static str> {
953	    match sort_class(s) {
954	        SortClass::Pub => Some("LSortPub"),
955	        SortClass::Fresh => Some("LSortFresh"),
956	        SortClass::Msg | SortClass::Node | SortClass::Nat => None,
957	    }
958	}
959	
960	/// Collect `(name,LSort)` tokens for every quantified variable of a disallowed
961	/// sort, visiting outer binders before inner ones (binding order).
962	fn wrong_quant_sorts(f: &Formula, out: &mut Vec<String>) {
963	    match f {
964	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
965	            for v in vs {
966	                if let Some(ls) = wrong_lsort(v.sort) {
967	                    out.push(format!("(\"{}\",{})", v.name, ls));
968	                }
969	            }
970	            wrong_quant_sorts(g, out);
971	        }
972	        Formula::Not(g) => wrong_quant_sorts(g, out),
973	        Formula::And(a, b)
974	        | Formula::Or(a, b)
975	        | Formula::Implies(a, b)
976	        | Formula::Iff(a, b) => {
977	            wrong_quant_sorts(a, out);
978	            wrong_quant_sorts(b, out);
979	        }
980	        _ => {}
981	    }
982	}
983	
984	fn quantifier_sorts_entry(entity: &str, name: &str, f: &Formula) -> Option<String> {
985	    let mut tokens = Vec::new();
986	    wrong_quant_sorts(f, &mut tokens);
987	    if tokens.is_empty() {
988	        return None;
989	    }
990	    let prefix = format!("  {} `{}' uses quantifiers with wrong sort:", entity, name);
991	    Some(fill_after_prefix(&prefix, &tokens, 4, FILL_WIDTH))
992	}
