994	// ---------------------------------------------------------------------------
995	// Formula terms (ill-formed terms in lemma / restriction formulas)
996	// ---------------------------------------------------------------------------
997	// A lemma/restriction formula may only use terms built from public constants
998	// and BOUND node/message variables via non-reducible function symbols. A term
999	// is reported "of the wrong form" if it contains a FREE variable or a REDUCIBLE
1000	// function symbol. The whole offending top-level term (each argument of each
1001	// atom) is reported, rendered in the oracle's raw term representation:
1002	//   - a bound variable  -> `Bound N` (de Bruijn: 0 = innermost binder)
1003	//   - a free  variable  -> `Free <pp_var>`  (keeps the sort prefix)
1004	//   - a function app    -> `f(a,b)`  (args comma-joined, NO space)
1005	//   - a tuple           -> `pair(a,pair(b,c))` (right-nested binary pairs)
1006	//   - a public constant -> `'name'`
1007	// The set of reducible function symbol names is caller-supplied (the caller
1008	// computes reducibility from the equation theory / Maude); this module only
1009	// consumes it. `formula_terms` is the zero-reducible-symbols convenience
1010	// wrapper (free variables only). See BEHAVIOR.md.
1011	
1012	const FORMULA_TERMS_HELP: &str = "  The only allowed terms are public constants and bound node and\n  message variables. If you encounter free message variables, then\n  you might have forgotten a #-prefix. Sort prefixes can only be\n  dropped where this is unambiguous. Moreover, reducible function\n  symbols are disallowed.";
1013	
1014	/// De Bruijn index of `(name, class)` on the binder stack (outermost pushed
1015	/// first): the innermost binder matching BOTH name and class is 0. `None` if no
1016	/// binder matches (the variable is free). Every quantified variable - including
1017	/// temporals and sort-mismatched ones - occupies one stack slot, so the index
1018	/// counts all binders between the use and its matching binder.
1019	fn debruijn_index(stack: &[Binder], name: &str, class: SortClass) -> Option<usize> {
1020	    stack
1021	        .iter()
1022	        .rposition(|(n, c)| n == name && *c == class)
1023	        .map(|pos| stack.len() - 1 - pos)
1024	}
1025	
1026	/// Render a term in the oracle's raw "wrong form" representation.
1027	fn show_wf_term(t: &Term, stack: &[Binder]) -> String {
1028	    match t {
1029	        Term::Var(v) => match debruijn_index(stack, &v.name, var_class(v)) {
1030	            Some(idx) => format!("Bound {}", idx),
1031	            None => format!("Free {}", pp_var(v)),
1032	        },
1033	        Term::PubLit(s) => format!("'{}'", s),
1034	        Term::FreshLit(s) => format!("~'{}'", s),
1035	        Term::NatLit(s) => format!("%'{}'", s),
1036	        Term::Number(n) => n.to_string(),
1037	        Term::NumberOne => "1".to_string(),
1038	        Term::NatOne => "%1".to_string(),
1039	        Term::DhNeutral => "DH_neutral".to_string(),
1040	        Term::App(name, args) => {
1041	            if args.is_empty() {
1042	                name.clone()
1043	            } else {
1044	                let parts: Vec<String> = args.iter().map(|a| show_wf_term(a, stack)).collect();
1045	                format!("{}({})", name, parts.join(","))
1046	            }
1047	        }
1048	        Term::AlgApp(name, a, b) => {
1049	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
1050	        }
1051	        Term::Pair(items) => show_wf_pair(items, stack),
1052	        Term::Diff(a, b) => {
1053	            format!("diff({},{})", show_wf_term(a, stack), show_wf_term(b, stack))
1054	        }
1055	        Term::BinOp(op, a, b) => {
1056	            let name = match op {
1057	                BinOp::Exp => "exp",
1058	                BinOp::Mult => "mult",
1059	                BinOp::Union => "union",
1060	                BinOp::Xor => "xor",
1061	                BinOp::NatPlus => "tadd",
1062	            };
1063	            format!("{}({},{})", name, show_wf_term(a, stack), show_wf_term(b, stack))
1064	        }
1065	        Term::PatMatch(inner) => show_wf_term(inner, stack),
1066	    }
1067	}
1068	
1069	/// Render a tuple as right-nested binary `pair(...)` applications.
1070	fn show_wf_pair(items: &[Term], stack: &[Binder]) -> String {
1071	    match items {
1072	        [] => "pair".to_string(),
1073	        [only] => show_wf_term(only, stack),
1074	        [head, rest @ ..] => {
1075	            format!("pair({},{})", show_wf_term(head, stack), show_wf_pair(rest, stack))
1076	        }
1077	    }
1078	}
1079	
1080	/// True iff `t` contains a free variable or a reducible function symbol, i.e.
1081	/// the term is "of the wrong form" for a trace formula.
1082	fn term_is_ill_formed(
1083	    t: &Term,
1084	    stack: &[Binder],
1085	    reducible: &std::collections::BTreeSet<String>,
1086	) -> bool {
1087	    match t {
1088	        Term::Var(v) => debruijn_index(stack, &v.name, var_class(v)).is_none(), // free -> ill
1089	        Term::PubLit(_)
1090	        | Term::FreshLit(_)
1091	        | Term::NatLit(_)
1092	        | Term::Number(_)
1093	        | Term::NumberOne
1094	        | Term::NatOne
1095	        | Term::DhNeutral => false,
1096	        Term::App(name, args) => {
1097	            reducible.contains(name) || args.iter().any(|a| term_is_ill_formed(a, stack, reducible))
1098	        }
1099	        Term::AlgApp(name, a, b) => {
1100	            reducible.contains(name)
1101	                || term_is_ill_formed(a, stack, reducible)
1102	                || term_is_ill_formed(b, stack, reducible)
1103	        }
1104	        Term::Pair(items) => items.iter().any(|a| term_is_ill_formed(a, stack, reducible)),
1105	        Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1106	            term_is_ill_formed(a, stack, reducible) || term_is_ill_formed(b, stack, reducible)
1107	        }
1108	        Term::PatMatch(inner) => term_is_ill_formed(inner, stack, reducible),
1109	    }
1110	}
1111	
1112	/// The argument terms of an atom, in the oracle's reporting order. For an
1113	/// action atom the TEMPORAL variable is reported before the fact arguments
1114	/// (observed via probe r3_actord).
1115	fn atom_terms(a: &Atom) -> Vec<&Term> {
1116	    match a {
1117	        Atom::Eq(x, y) | Atom::Less(x, y) | Atom::LessMset(x, y) | Atom::Subterm(x, y) => {
1118	            vec![x, y]
1119	        }
1120	        Atom::Action(f, t) => {
1121	            let mut v = vec![t];
1122	            v.extend(f.args.iter());
1123	            v
1124	        }
1125	        Atom::Last(t) => vec![t],
1126	        Atom::Pred(f) => f.args.iter().collect(),
1127	    }
1128	}
1129	
1130	/// Walk a formula in source order collecting the RENDERED strings of every
1131	/// ill-formed atom term. Not deduplicated (probe r3_shapes: `x = y & x = y`
1132	/// reports `Free y` twice). Every quantified variable pushes a `(name, class)`
1133	/// binder, so uses are matched sort-aware.
1134	fn collect_ill_terms(
1135	    f: &Formula,
1136	    stack: &mut Vec<Binder>,
1137	    reducible: &std::collections::BTreeSet<String>,
1138	    out: &mut Vec<String>,
1139	) {
1140	    match f {
1141	        Formula::False | Formula::True => {}
1142	        Formula::Atom(a) => {
1143	            for t in atom_terms(a) {
1144	                if term_is_ill_formed(t, stack, reducible) {
1145	                    out.push(show_wf_term(t, stack));
1146	                }
1147	            }
1148	        }
1149	        Formula::Not(g) => collect_ill_terms(g, stack, reducible, out),
1150	        Formula::And(a, b)
1151	        | Formula::Or(a, b)
1152	        | Formula::Implies(a, b)
1153	        | Formula::Iff(a, b) => {
1154	            collect_ill_terms(a, stack, reducible, out);
1155	            collect_ill_terms(b, stack, reducible, out);
1156	        }
1157	        Formula::Forall(vs, g) | Formula::Exists(vs, g) => {
1158	            let n = vs.len();
1159	            for v in vs {
1160	                stack.push((v.name.clone(), var_class(v)));
1161	            }
1162	            collect_ill_terms(g, stack, reducible, out);
1163	            for _ in 0..n {
1164	                stack.pop();
1165	            }
1166	        }
1167	    }
1168	}
1169	
1170	fn ill_terms(f: &Formula, reducible: &std::collections::BTreeSet<String>) -> Vec<String> {
1171	    let mut stack: Vec<Binder> = Vec::new();
1172	    let mut terms: Vec<String> = Vec::new();
1173	    collect_ill_terms(f, &mut stack, reducible, &mut terms);
1174	    terms
1175	}
