1214	/// Standalone "Formula terms" check: reports ill-formed terms (free variables
1215	/// and applications of any symbol in `reducible`) in every lemma (source order)
1216	/// then every restriction (source order), merged into one topic block.
1217	pub fn formula_terms_reducible(
1218	    thy: &Theory,
1219	    reducible: &std::collections::BTreeSet<String>,
1220	) -> Vec<WfError> {
1221	    let mut entries: Vec<String> = Vec::new();
1222	    for (entity, name, formula, _) in formula_items(thy) {
1223	        let terms = ill_terms(formula, reducible);
1224	        if !terms.is_empty() {
1225	            entries.push(formula_terms_entry(entity, name, &terms));
1226	        }
1227	    }
1228	    if entries.is_empty() {
1229	        vec![]
1230	    } else {
1231	        vec![WfError::new(T_FORMULA_TERMS, entries.join("\n  \n"))]
1232	    }
1233	}
