1366	// ---------------------------------------------------------------------------
1367	// Formula-check bundle (Quantifier sorts, Formula terms, Formula guardedness)
1368	// ---------------------------------------------------------------------------
1369	// The three per-formula checks are run together, item by item, in the oracle's
1370	// checking order: every lemma (source order) first, then every restriction
1371	// (source order). For each item the three topics are emitted in the order
1372	// Quantifier sorts, Formula terms, Formula guardedness (guardedness for lemmas
1373	// only). Consecutive entries sharing a topic merge under a single header; a
1374	// topic that recurs after an intervening different topic starts a fresh block
1375	// (observed: L1=QS, L2=FT, L3=QS renders as three blocks).
1376	
1377	/// The formula-bearing items in checking order: (entity, name, formula,
1378	/// is_lemma). Lemmas come before restrictions regardless of source order.
1379	fn formula_items(thy: &Theory) -> Vec<(&'static str, &str, &Formula, bool)> {
1380	    let mut out: Vec<(&'static str, &str, &Formula, bool)> = Vec::new();
1381	    for it in &thy.items {
1382	        if let TheoryItem::Lemma(l) = it {
1383	            out.push(("Lemma", l.name.as_str(), &l.formula, true));
1384	        }
1385	    }
1386	    for it in &thy.items {
1387	        if let TheoryItem::Restriction(r) | TheoryItem::LegacyAxiom(r) = it {
1388	            out.push(("Restriction", r.name.as_str(), &r.formula, false));
1389	        }
1390	    }
1391	    out
1392	}
1393	
1394	/// Merge a sequence of `(topic, entry)` pairs, joining only CONSECUTIVE
1395	/// same-topic entries (separator `"\n  \n"`) into one `WfError` block.
1396	fn merge_consecutive(seq: Vec<(&'static str, String)>) -> Vec<WfError> {
1397	    let mut out: Vec<WfError> = Vec::new();
1398	    for (topic, entry) in seq {
1399	        if let Some(last) = out.last_mut() {
1400	            if last.topic == topic {
1401	                last.message.push_str("\n  \n");
1402	                last.message.push_str(&entry);
1403	                continue;
1404	            }
1405	        }
1406	        out.push(WfError::new(topic, entry));

1407	    }
1408	    out
1409	}
1410	
1411	/// Run the Quantifier-sorts / Formula-terms / Formula-guardedness bundle over
1412	/// all lemmas and restrictions, producing the merged topic blocks in report
1413	/// order.
1414	pub fn formula_reports(
1415	    thy: &Theory,
1416	    reducible: &std::collections::BTreeSet<String>,
1417	) -> Vec<WfError> {
1418	    let mut seq: Vec<(&'static str, String)> = Vec::new();
1419	    for (entity, name, formula, is_lemma) in formula_items(thy) {
1420	        if let Some(e) = quantifier_sorts_entry(entity, name, formula) {
1421	            seq.push((T_QUANT_SORTS, e));
1422	        }
1423	        let terms = ill_terms(formula, reducible);
1424	        if !terms.is_empty() {
1425	            seq.push((T_FORMULA_TERMS, formula_terms_entry(entity, name, &terms)));
1426	        }
1427	        if is_lemma {
1428	            if let Some(e) = guardedness_entry(name, formula) {
1429	                seq.push((T_GUARD, e));
1430	            }
1431	        }
1432	    }
1433	    merge_consecutive(seq)
1434	}
