1438	// ---------------------------------------------------------------------------
1439	
1440	pub fn nat_sorts(thy: &Theory) -> Vec<WfError> {
1441	    let mut entries: Vec<String> = Vec::new();
1442	    for r in protocol_rules(thy) {
1443	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1444	            for f in facts {
1445	                for a in &f.args {
1446	                    collect_nat_issues(a, &mut entries);
1447	                }
1448	            }
1449	        }
1450	    }
1451	    if entries.is_empty() {
1452	        vec![]
1453	    } else {
1454	        vec![WfError::new(T_NAT, entries.join("\n  \n"))]
1455	    }
1456	}
1457	
1458	fn collect_nat_issues(t: &Term, out: &mut Vec<String>) {
1459	    if let Term::BinOp(BinOp::NatPlus, _, _) = t {
1460	        let term_pp = pp_term(t);
1461	        let mut vs = Vec::new();
1462	        collect_term_vars(t, &mut vs);
1463	        for v in vs {
1464	            if v.sort != SortHint::Nat {
1465	                let entry = format!("  {} in term {} must be of sort nat", pp_var(&v), term_pp);
1466	                if !out.contains(&entry) {
1467	                    out.push(entry);
1468	                }
1469	            }
1470	        }
1471	    }
1472	    // recurse
1473	    match t {
1474	        Term::App(_, args) | Term::Pair(args) => {
1475	            for a in args {
1476	                collect_nat_issues(a, out);
1477	            }
1478	        }
1479	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1480	            collect_nat_issues(a, out);
1481	            collect_nat_issues(b, out);
1482	        }
1483	        Term::PatMatch(inner) => collect_nat_issues(inner, out),
1484	        _ => {}
1485	    }
1486	}
1487	
1488	// ---------------------------------------------------------------------------
1489	// 13. Subterm Convergence Warning
1490	// ---------------------------------------------------------------------------
1491	
1492	pub fn subterm_convergence(thy: &Theory) -> Vec<WfError> {
1493	    let mut bad: Vec<String> = Vec::new();
1494	    for it in &thy.items {
1495	        if let TheoryItem::Equations { convergent, eqs } = it {
1496	            if *convergent {
1497	                continue; // user asserted convergence
1498	            }
1499	            for eq in eqs {
1500	                if !is_subterm(&eq.rhs, &eq.lhs) {
1501	                    bad.push(format!("    {} = {}", pp_term(&eq.lhs), pp_term(&eq.rhs)));
1502	                }
1503	            }
1504	        }
1505	    }
1506	    if bad.is_empty() {
1507	        return vec![];
1508	    }
1509	    let intro = "  User-defined equations must be convergent and have the finite variant property. The following equations are not subterm convergent. If you are sure that the set of equations is nevertheless convergent and has the finite variant property, you can ignore this warning and continue ";
1510	    let manual = " For more information, please refer to the manual : https://tamarin-prover.com/manual/master/book/010_modeling-issues.html ";
1511	    let msg = format!("{}\n\n{}\n   \n{}", intro, bad.join("\n"), manual);
1512	    vec![WfError::new(T_SUBTERM, msg)]
1513	}
1514	
1515	/// Structural subterm test: does `small` occur as a subterm of `big`?
1516	fn is_subterm(small: &Term, big: &Term) -> bool {
1517	    if small == big {
1518	        return true;
1519	    }
1520	    match big {
1521	        Term::App(_, args) | Term::Pair(args) => args.iter().any(|a| is_subterm(small, a)),
1522	        Term::AlgApp(_, a, b) | Term::Diff(a, b) | Term::BinOp(_, a, b) => {
1523	            is_subterm(small, a) || is_subterm(small, b)
1524	        }
1525	        Term::PatMatch(inner) => is_subterm(small, inner),
1526	        _ => false,
1527	    }
1528	}
1529	
1530	// ---------------------------------------------------------------------------
1531	// 2. Fresh public constants
1532	// ---------------------------------------------------------------------------
1533	// A fresh-name literal (`~'foo'`) used directly in a rule is rejected; fresh
1534	// names must come from `Fr(~x)` premises. Constants are collected in the order
1535	// premises, conclusions, actions (observed via probe fpc_positions).
1536	pub fn fresh_public_constants(thy: &Theory) -> Vec<WfError> {
1537	    let mut entries: Vec<String> = Vec::new();
1538	    for r in protocol_rules(thy) {
1539	        let mut lits: Vec<String> = Vec::new();
1540	        for facts in [&r.premises, &r.conclusions, &r.actions] {
1541	            for f in facts {
1542	                for a in &f.args {
1543	                    collect_fresh_lits(a, &mut lits);
1544	                }
1545	            }
1546	        }
1547	        if lits.is_empty() {
1548	            continue;
1549	        }
1550	        // The constant list is a fillSep wrapped at column 69 with a 4-space
1551	        // continuation indent (probe r3_freshwrap).
1552	        let prefix = format!(
1553	            "  rule `{}': fresh public constants are not allowed:",
1554	            r.name
1555	        );
1556	        entries.push(fill_after_prefix(&prefix, &lits, 4, FILL_WIDTH));
1557	    }
1558	    if entries.is_empty() {
1559	        vec![]
1560	    } else {
1561	        vec![WfError::new(T_FRESH_PUB, entries.join("\n  \n"))]
1562	    }
1563	}
1564	
1565	// ---------------------------------------------------------------------------
1566	// 5. Reserved prefixes (diff mode only)
1567	// ---------------------------------------------------------------------------
1568	// Fact names beginning with `DiffIntr`/`DiffProto` are reserved for the diff
1569	// translation. Only emitted for diff-mode theories (observed: silent otherwise).
1570	pub fn reserved_prefixes(thy: &Theory) -> Vec<WfError> {
1571	    if !thy.is_diff {
1572	        return vec![];
1573	    }
1574	    let mut entries: Vec<String> = Vec::new();
1575	    for r in protocol_rules(thy) {
1576	        // Order of collection: premises, actions, conclusions (probe rp_multi).
1577	        let mut hits: Vec<&Fact> = Vec::new();
1578	        for facts in [&r.premises, &r.actions, &r.conclusions] {
1579	            for f in facts {
1580	                if RESERVED_PREFIXES.iter().any(|p| f.name.starts_with(p)) {
1581	                    hits.push(f);
1582	                }
1583	            }
1584	        }
1585	        if hits.is_empty() {
1586	            continue;
1587	        }
1588	        let header = fill_words(&reserved_prefix_header_words(&r.name), 2, FILL_WIDTH);
1589	        let blocks: Vec<String> = hits
1590	            .iter()
1591	            .map(|f| {
1592	                let m = if f.persistent { "Persistent" } else { "Linear" };
1593	                format!(
1594	                    "    {}\n    (ProtoFact {} \"{}\" {},{},{})",
1595	                    pp_fact(f),
1596	                    m,
1597	                    f.name,
1598	                    f.args.len(),
1599	                    f.args.len(),
1600	                    m
1601	                )
1602	            })
1603	            .collect();
1604	        entries.push(format!("{}\n  \n{}", header, blocks.join("\n  \n")));
1605	    }
1606	    if entries.is_empty() {
1607	        vec![]
1608	    } else {
1609	        vec![WfError::new(T_RESERVED_PREFIX, entries.join("\n  \n"))]
1610	    }
1611	}
1612	
1613	fn reserved_prefix_header_words(rule: &str) -> Vec<String> {
1614	    [
1615	        "The",
1616	        "Rule",
1617	        &format!("`{}'", rule),
1618	        "contains",
1619	        "facts",
1620	        "with",
1621	        "reserved",
1622	        "prefixes",
1623	        "('DiffIntr',",
1624	        "'DiffProto')",
1625	        "inside",
1626	        "names:",
1627	    ]
1628	    .iter()
1629	    .map(|s| s.to_string())
1630	    .collect()
1631	}
1632	
1633	// ---------------------------------------------------------------------------
1634	// 11 & 12. Left rule / Right rule (diff mode only)
1635	// ---------------------------------------------------------------------------
1636	// A diff rule may carry explicit `left`/`right` projections. Each explicit
1637	// projection must equal the corresponding projection of the parent diff rule
1638	// (diff(a,b) -> a on the left, -> b on the right). When it differs, the rule is
1639	// "inconsistent". For a single rule the left projection is checked first and,
1640	// if inconsistent, the right is not reported (observed via probe diff_both).
1641	pub fn diff_left_right(thy: &Theory) -> Vec<WfError> {
1642	    if !thy.is_diff {
1643	        return vec![];
1644	    }
1645	    let mut left_entries: Vec<String> = Vec::new();
1646	    let mut right_entries: Vec<String> = Vec::new();
1647	    for r in protocol_rules(thy) {
1648	        if let Some((left, right)) = &r.left_right {
1649	            if !rule_matches_projection(r, left, true) {
1650	                left_entries.push(inconsistent_entry("left", left, r));
1651	            } else if !rule_matches_projection(r, right, false) {
1652	                right_entries.push(inconsistent_entry("right", right, r));
1653	            }
1654	        }
1655	    }
1656	    let mut out = Vec::new();
1657	    if !left_entries.is_empty() {
1658	        out.push(WfError::new(T_LEFT, left_entries.join("\n  \n")));
1659	    }
1660	    if !right_entries.is_empty() {
1661	        out.push(WfError::new(T_RIGHT, right_entries.join("\n  \n")));
1662	    }
1663	    out
1664	}
1665	
1666	fn inconsistent_entry(side: &str, explicit: &Rule, parent: &Rule) -> String {
1667	    format!(
1668	        "  Inconsistent {} rule\n{}\n  \n  w.r.t.\n  \n{}",
1669	        side,
1670	        indent_block(&pp_rule(explicit), 4),
1671	        indent_block(&pp_rule(parent), 4)
1672	    )
1673	}
1674	
1675	/// True iff the explicit rule's fact lists equal the parent rule's projection.
1676	fn rule_matches_projection(parent: &Rule, explicit: &Rule, left: bool) -> bool {
1677	    facts_pp(&project_facts(&parent.premises, left)) == facts_pp(&explicit.premises)
1678	        && facts_pp(&project_facts(&parent.actions, left)) == facts_pp(&explicit.actions)
1679	        && facts_pp(&project_facts(&parent.conclusions, left)) == facts_pp(&explicit.conclusions)
1680	}
1681	
1682	fn facts_pp(fs: &[Fact]) -> String {
1683	    fs.iter().map(pp_fact).collect::<Vec<_>>().join(", ")
1684	}
1685	
1686	fn project_facts(fs: &[Fact], left: bool) -> Vec<Fact> {
1687	    fs.iter().map(|f| project_fact(f, left)).collect()
1688	}
1689	
1690	fn project_fact(f: &Fact, left: bool) -> Fact {
1691	    Fact {
1692	        persistent: f.persistent,
1693	        name: f.name.clone(),
1694	        args: f.args.iter().map(|a| project_term(a, left)).collect(),
1695	        annotations: f.annotations.clone(),
1696	    }
1697	}
1698	
1699	/// Project a diff term to one side: `diff(a, b)` becomes `a` (left) or `b`
1700	/// (right); all other terms are structurally mapped.
1701	fn project_term(t: &Term, left: bool) -> Term {
1702	    match t {
1703	        Term::Diff(a, b) => project_term(if left { a } else { b }, left),
1704	        Term::App(name, args) => {
1705	            Term::App(name.clone(), args.iter().map(|a| project_term(a, left)).collect())
1706	        }
1707	        Term::Pair(args) => Term::Pair(args.iter().map(|a| project_term(a, left)).collect()),
1708	        Term::AlgApp(name, a, b) => Term::AlgApp(
1709	            name.clone(),
1710	            Box::new(project_term(a, left)),
1711	            Box::new(project_term(b, left)),
1712	        ),
1713	        Term::BinOp(op, a, b) => Term::BinOp(
1714	            *op,
1715	            Box::new(project_term(a, left)),
1716	            Box::new(project_term(b, left)),
1717	        ),
1718	        Term::PatMatch(inner) => Term::PatMatch(Box::new(project_term(inner, left))),
1719	        other => other.clone(),
1720	    }
1721	}
