1724	// 15. Lemma annotations
1725	// ---------------------------------------------------------------------------
1726	// An `exists-trace` lemma marked `reuse` is rejected (observed trigger).
1727	pub fn lemma_annotations(thy: &Theory) -> Vec<WfError> {
1728	    let mut entries: Vec<String> = Vec::new();
1729	    for it in &thy.items {
1730	        if let TheoryItem::Lemma(l) = it {
1731	            let is_reuse = l.attributes.iter().any(|a| matches!(a, LemmaAttr::Reuse));
1732	            if is_reuse && l.trace_quantifier == TraceQuantifier::ExistsTrace {
1733	                entries.push(format!(
1734	                    "  Lemma `{}': cannot reuse 'exists-trace' lemmas",
1735	                    l.name
1736	                ));
1737	            }
1738	        }
1739	    }
1740	    if entries.is_empty() {
1741	        vec![]
1742	    } else {
1743	        vec![WfError::new(T_LEMMA_ANNOT, entries.join("\n  \n"))]
1744	    }
1745	}
