1747	// ---------------------------------------------------------------------------
1748	// 16. Multiplication restriction of rules
1749	// ---------------------------------------------------------------------------
1750	// A rule whose conclusions contain a multiplication (`*`) term is not
1751	// multiplication restricted. The "After replacing reducible function symbols"
1752	// rule renders identically to the original when the left-hand side has no
1753	// reducible symbols to replace (the general replacement is a documented gap).
1754	pub fn multiplication_restriction(thy: &Theory) -> Vec<WfError> {
1755	    let mut entries: Vec<String> = Vec::new();
1756	    for r in protocol_rules(thy) {
1757	        let mut mult_terms: Vec<String> = Vec::new();
1758	        for f in &r.conclusions {
1759	            for a in &f.args {
1760	                collect_mult_terms(a, &mut mult_terms);
1761	            }
1762	        }
1763	        if mult_terms.is_empty() {
1764	            continue;
1765	        }
1766	        let rule_pp = indent_block(&pp_rule(r), 4);
1767	        entries.push(format!(
1768	            "  The following rule is not multiplication restricted:\n{rule}\n  \n  After replacing reducible function symbols in lhs with variables:\n{rule}\n  \n    Terms with multiplication:  {terms}",
1769	            rule = rule_pp,
1770	            terms = mult_terms.join(", ")
1771	        ));
1772	    }
1773	    if entries.is_empty() {
1774	        vec![]
1775	    } else {
1776	        vec![WfError::new(T_MULRESTRICT, entries.join("\n  \n"))]
1777	    }
1778	}
