/// A variable's sort+name representation without the numeric index.
fn variant_repr(v: &VarSpec) -> String {
    let prefix = match v.sort {
        SortHint::Fresh => "~",
        SortHint::Pub => "$",
        SortHint::Nat => "%",
        SortHint::Node => "#",
        _ => "",
    };
    format!("{}{}", prefix, v.name)
}

