#[test]
fn sorts_variant_order_is_sort_then_name() {
    // s5_crossname: ~X with $x -> "$x, ~X" (sort rank beats name order).
    let thy = theory("T", vec![rule(
        "R1",
        vec![
            fact("Fr", vec![fresh("X")]),
            fact("In", vec![pub_("x")]),
        ],
        vec![fact("M", vec![fresh("X"), pub_("x")])],
